        if (this.nisConfiguration().ignoreFees()) {
            NemGlobals.setTransactionFeeCalculator(new ZeroTransactionFeeCalculator());
        } else {
            NemGlobals.setTransactionFeeCalculator(new DefaultTransactionFeeCalculator(adapters.asMosaicFeeInformationLookup(), () -> this.blockChainLastBlockLayer.getLastBlockHeight().next(), new BlockHeight[] { new BlockHeight(BlockMarkerConstants.FEE_FORK(this.nisConfiguration().getNetworkInfo().getVersion() << 24)), new BlockHeight(BlockMarkerConstants.SECOND_FEE_FORK(this.nisConfiguration().getNetworkInfo().getVersion() << 24)) }));
        }
        NemGlobals.setBlockChainConfiguration(this.nisConfiguration().getBlockChainConfiguration());
        NemStateGlobals.setWeightedBalancesSupplier(this.weighedBalancesSupplier());
        return new NisMain(this.blockDao, this.nisCache(), this.networkHostBootstrapper(), this.nisModelToDbModelMapper(), this.nisConfiguration(), this.blockAnalyzer(), System::exit);
