        return new BlockAnalyzer(this.blockDao, this.blockChainUpdater(), this.blockChainLastBlockLayer, this.nisMapperFactory(), estimatedBlocksPerYear);
    }

    @Bean
    public HttpConnectorPool httpConnectorPool() {
        final CommunicationMode communicationMode = this.nisConfiguration().useBinaryTransport() ? CommunicationMode.BINARY : CommunicationMode.JSON;
        return new HttpConnectorPool(communicationMode, this.outgoingAudits());
    }

    @Bean
    public NisPeerNetworkHost nisPeerNetworkHost() {
        final HarvestingTask harvestingTask = new HarvestingTask(this.blockChain(), this.harvester(), this.unconfirmedTransactions());
        final PeerNetworkScheduler scheduler = new PeerNetworkScheduler(this.timeProvider(), harvestingTask);
        final CountingBlockSynchronizer synchronizer = new CountingBlockSynchronizer(this.blockChain());
        return new NisPeerNetworkHost(this.nisCache(), synchronizer, scheduler, this.chainServices(), this.nodeCompatibilityChecker(), this.nisConfiguration(), this.httpConnectorPool(), this.trustProvider(), this.incomingAudits(), this.outgoingAudits());
