    private static final int MAX_AUDIT_HISTORY_SIZE = 50;

    @Bean
    protected AuditCollection outgoingAudits() {
        return this.createAuditCollection();
    }

    @Bean
    protected AuditCollection incomingAudits() {
        return this.createAuditCollection();
    }

    private AuditCollection createAuditCollection() {
        return new AuditCollection(MAX_AUDIT_HISTORY_SIZE, this.timeProvider());
    }

    @Bean
    public DataSource dataSource() throws IOException {
        final NisConfiguration configuration = this.nisConfiguration();
        final String nemFolder = configuration.getNemFolder();
        final Properties prop = new Properties();
        prop.load(NisAppConfig.class.getClassLoader().getResourceAsStream("db.properties"));
        // replace url parameters with values from configuration
        final String jdbcUrl = prop.getProperty("jdbc.url").replace("${nem.folder}", nemFolder).replace("${nem.network}", configuration.getNetworkName());
        final DriverManagerDataSource dataSource = new DriverManagerDataSource();
        dataSource.setDriverClassName(prop.getProperty("jdbc.driverClassName"));
        dataSource.setUrl(jdbcUrl);
        dataSource.setUsername(prop.getProperty("jdbc.username"));
        dataSource.setPassword(prop.getProperty("jdbc.password"));
        return dataSource;
    }

    @Bean(initMethod = "migrate")
    public Flyway flyway() throws IOException {
        final Properties prop = new Properties();
        prop.load(NisAppConfig.class.getClassLoader().getResourceAsStream("db.properties"));
        return Flyway.configure().dataSource(this.dataSource()).classLoader(NisAppConfig.class.getClassLoader()).locations(prop.getProperty("flyway.locations")).validateOnMigrate(Boolean.valueOf(prop.getProperty("flyway.validate"))).load();
    }

    @Bean
    @DependsOn("flyway")
    public SessionFactory sessionFactory() throws IOException {
        return SessionFactoryLoader.load(this.dataSource());
    }

    @Bean
    public BlockChain blockChain() {
        return new BlockChain(this.blockChainLastBlockLayer, this.blockChainUpdater());
    }

    @Bean
    public BlockChainServices blockChainServices() {
        return new BlockChainServices(this.blockDao, this.blockTransactionObserverFactory(), this.blockValidatorFactory(), this.transactionValidatorFactory(), this.nisMapperFactory(), this.nisConfiguration().getForkConfiguration());
    }

    @Bean
    public BlockChainUpdater blockChainUpdater() {
        return new BlockChainUpdater(this.nisCache(), this.blockChainLastBlockLayer, this.blockDao, this.blockChainContextFactory(), this.unconfirmedTransactions(), this.nisConfiguration());
